const express = require('express');
const axios = require('axios');
const vm = require('vm');

const app = express();
app.use(express.json());

const AI_API_URL = 'https://api.example.com/generate-code'; // Replace with actual AI API URL
const AI_API_KEY = 'your-api-key'; // Replace with your API key

app.post('/generate-code', async (req, res) => {
  try {
    const userPrompt = req.body.prompt;
    if (!userPrompt) {
      return res.status(400).send('Prompt is required');
    }

    const aiResponse = await axios.post(AI_API_URL, {
      prompt: userPrompt,
      apiKey: AI_API_KEY
    });

    const generatedCode = aiResponse.data.code;
    if (!generatedCode) {
      return res.status(500).send('Failed to generate code');
    }

    const sandbox = {};
    const script = new vm.Script(generatedCode);
    const context = new vm.createContext(sandbox);

    script.runInContext(context);

    res.json({ result: sandbox.result });
  } catch (error) {
    console.error('Error:', error);
    res.status(500).send('Internal Server Error');
  }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});